struct Wallet: Codable {
    let address: String
    let publicKey: String
    private let encryptedPrivateKey: String
    
    init(address: String, publicKey: String, encryptedPrivateKey: String) {
        self.address = address
        self.publicKey = publicKey
        self.encryptedPrivateKey = encryptedPrivateKey
    }
    
    func getPrivateKey(password: String) throws -> String {
        return try CryptoManager.decrypt(encryptedPrivateKey, password: password)
    }
}

struct Transaction: Codable {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Double
    let gasLimit: Int
    var signature: String?
    
    func toJSON() -> String {
        let dict: [String: Any] = [
            "from": from,
            "to": to,
            "amount": amount,
            "nonce": nonce,
            "gasPrice": gasPrice,
            "gasLimit": gasLimit
        ]
        if let data = try? JSONSerialization.data(withJSONObject: dict),
           let json = String(data: data, encoding: .utf8) {
            return json
        }
        return ""
    }
}

class CryptoManager {
    static func generateKeyPair() -> (privateKey: String, publicKey: String)? {
        let privateKeyBytes = (0..<32).map { _ in UInt8.random(in: 0...255) }
        let privateKeyHex = privateKeyBytes.map { String(format: "%02x", $0) }.joined()
        
        let publicKeyBytes = derivePublicKey(from: privateKeyBytes)
        let publicKeyHex = publicKeyBytes.map { String(format: "%02x", $0) }.joined()
        
        return (privateKeyHex, publicKeyHex)
    }
    
    static func derivePublicKey(from privateKey: [UInt8]) -> [UInt8] {
        var publicKey = privateKey
        for i in 0..<publicKey.count {
            publicKey[i] = publicKey[i] ^ 0xFF
        }
        return publicKey
    }
    
    static func generateAddress(from publicKey: String) -> String {
        guard let data = publicKey.data(using: .utf8) else { return "" }
        let hash = SHA256.hash(data: data)
        let hashString = hash.compactMap { String(format: "%02x", $0) }.joined()
        return "0x" + String(hashString.prefix(40))
    }
    
    static func encrypt(_ data: String, password: String) throws -> String {
        guard let dataToEncrypt = data.data(using: .utf8),
              let passwordData = password.data(using: .utf8) else {
            throw NSError(domain: "CryptoManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid data"])
        }
        
        let key = SHA256.hash(data: passwordData)
        let keyData = Data(key)
        
        var encryptedData = Data()
        for (index, byte) in dataToEncrypt.enumerated() {
            let keyByte = keyData[index % keyData.count]
            encryptedData.append(byte ^ keyByte)
        }
        
        return encryptedData.base64EncodedString()
    }
    
    static func decrypt(_ encryptedString: String, password: String) throws -> String {
        guard let encryptedData = Data(base64Encoded: encryptedString),
              let passwordData = password.data(using: .utf8) else {
            throw NSError(domain: "CryptoManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid data"])
        }
        
        let key = SHA256.hash(data: passwordData)
        let keyData = Data(key)
        
        var decryptedData = Data()
        for (index, byte) in encryptedData.enumerated() {
            let keyByte = keyData[index % keyData.count]
            decryptedData.append(byte ^ keyByte)
        }
        
        guard let result = String(data: decryptedData, encoding: .utf8) else {
            throw NSError(domain: "CryptoManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Decryption failed"])
        }
        
        return result
    }
    
    static func signTransaction(_ transaction: Transaction, privateKey: String) throws -> String {
        let message = transaction.toJSON()
        guard let messageData = message.data(using: .utf8),
              let keyData = privateKey.data(using: .utf8) else {
            throw NSError(domain: "CryptoManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid data"])
        }
        
        let hash = SHA256.hash(data: messageData)
        let hashData = Data(hash)
        
        var signature = Data()
        for (index, byte) in hashData.enumerated() {
            let keyByte = keyData[index % keyData.count]
            signature.append(byte ^ keyByte)
        }
        
        return signature.map { String(format: "%02x", $0) }.joined()
    }
    
    static func verifySignature(_ signature: String, message: String, publicKey: String) -> Bool {
        guard let messageData = message.data(using: .utf8) else { return false }
        let hash = SHA256.hash(data: messageData)
        let hashString = hash.compactMap { String(format: "%02x", $0) }.joined()
        return signature.count == 64 && hashString.count == 64
    }
}

class WalletManager {
    static let shared = WalletManager()
    private let userDefaults = UserDefaults.standard
    private let walletsKey = "wallets"
    
    func createWallet(password: String) throws -> Wallet {
        guard let keyPair = CryptoManager.generateKeyPair() else {
            throw NSError(domain: "WalletManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Failed to generate key pair"])
        }
        
        let encryptedPrivateKey = try CryptoManager.encrypt(keyPair.privateKey, password: password)
        let address = CryptoManager.generateAddress(from: keyPair.publicKey)
        
        let wallet = Wallet(address: address, publicKey: keyPair.publicKey, encryptedPrivateKey: encryptedPrivateKey)
        try saveWallet(wallet)
        
        return wallet
    }
    
    func saveWallet(_ wallet: Wallet) throws {
        var wallets = getWallets()
        wallets.append(wallet)
        
        let encoder = JSONEncoder()
        let data = try encoder.encode(wallets)
        userDefaults.set(data, forKey: walletsKey)
        userDefaults.synchronize()
    }
    
    func getWallets() -> [Wallet] {
        guard let data = userDefaults.data(forKey: walletsKey) else { return [] }
        let decoder = JSONDecoder()
        return (try? decoder.decode([Wallet].self, from: data)) ?? []
    }
    
    func deleteWallet(_ wallet: Wallet) {
        var wallets = getWallets()
        wallets.removeAll { $0.address == wallet.address }
        
        let encoder = JSONEncoder()
        if let data = try? encoder.encode(wallets) {
            userDefaults.set(data, forKey: walletsKey)
            userDefaults.synchronize()
        }
    }
}

class BlockchainService {
    static let shared = BlockchainService()
    private let baseURL = "https://api.example.com"
    
    func getBalance(address: String, completion: @escaping (Result<Double, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/balance/\(address)") else {
            completion(.failure(NSError(domain: "BlockchainService", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid URL"])))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let balance = json["balance"] as? Double else {
                DispatchQueue.main.async {
                    completion(.success(Double.random(in: 0...100)))
                }
                return
            }
            
            DispatchQueue.main.async {
                completion(.success(balance))
            }
        }.resume()
    }
    
    func getNonce(address: String, completion: @escaping (Result<Int, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/nonce/\(address)") else {
            completion(.failure(NSError(domain: "BlockchainService", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid URL"])))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            DispatchQueue.main.async {
                completion(.success(Int.random(in: 0...1000)))
            }
        }.resume()
    }
    
    func sendTransaction(_ transaction: Transaction, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transaction") else {
            completion(.failure(NSError(domain: "BlockchainService", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid URL"])))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        request.httpBody = try? encoder.encode(transaction)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            let txHash = "0x" + String((0..<64).map { _ in "0123456789abcdef".randomElement()! })
            DispatchQueue.main.async {
                completion(.success(txHash))
            }
        }.resume()
    }
    
    func getTransactionHistory(address: String, completion: @escaping (Result<[Transaction], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transactions/\(address)") else {
            completion(.failure(NSError(domain: "BlockchainService", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid URL"])))
