class SendTransactionViewController: UIViewController {
    private let wallet: Wallet
    private let toAddressField = UITextField()
    private let amountField = UITextField()
    private let sendButton = UIButton()
    
    init(wallet: Wallet) {
        self.wallet = wallet
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Send Transaction"
        
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stackView)
        
        toAddressField.placeholder = "Recipient Address"
        toAddressField.borderStyle = .roundedRect
        toAddressField.autocapitalizationType = .none
        
        amountField.placeholder = "Amount"
        amountField.borderStyle = .roundedRect
        amountField.keyboardType = .decimalPad
        
        sendButton.setTitle("Send Transaction", for: .normal)
        sendButton.backgroundColor = .systemBlue
        sendButton.layer.cornerRadius = 8
        sendButton.addTarget(self, action: #selector(sendTransaction), for: .touchUpInside)
        sendButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        
        stackView.addArrangedSubview(toAddressField)
        stackView.addArrangedSubview(amountField)
        stackView.addArrangedSubview(sendButton)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20)
        ])
        
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    @objc private func sendTransaction() {
        guard let toAddress = toAddressField.text, !toAddress.isEmpty,
              let amountString = amountField.text,
              let amount = Double(amountString), amount > 0 else {
            showError("Please fill in all fields correctly")
            return
        }
        
        let alert = UIAlertController(title: "Confirm Transaction", message: "Enter your password to sign the transaction", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Password"
            textField.isSecureTextEntry = true
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let password = alert.textFields?[0].text,
                  let self = self else { return }
            
            self.processTransaction(to: toAddress, amount: amount, password: password)
        })
        
        present(alert, animated: true)
    }
    
    private func processTransaction(to: String, amount: Double, password: String) {
        BlockchainService.shared.getNonce(address: wallet.address) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let nonce):
                do {
                    let privateKey = try self.wallet.getPrivateKey(password: password)
                    
                    var transaction = Transaction(
                        from: self.wallet.address,
                        to: to,
                        amount: amount,
                        nonce: nonce,
                        gasPrice: 0.00001,
                        gasLimit: 21000,
                        signature: nil
                    )
                    
                    let signature = try CryptoManager.signTransaction(transaction, privateKey: privateKey)
                    transaction.signature = signature
                    
                    BlockchainService.shared.sendTransaction(transaction) { result in
                        switch result {
                        case .success(let txHash):
                            self.showSuccess("Transaction sent!\nTx Hash: \(txHash)")
                            DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
                                self.navigationController?.popViewController(animated: true)
                            }
                        case .failure(let error):
                            self.showError("Failed to send transaction: \(error.localizedDescription)")
                        }
                    }
                } catch {
                    self.showError("Invalid password or signing error")
                }
            case .failure(let error):
                self.showError("Failed to get nonce: \(error.localizedDescription)")
            }
        }
    }
    
    private func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSuccess(_ message: String) {
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

